import React, { useState } from 'react';

const SetlistCreator = () => {
  const [search, setSearch] = useState('');
  const [setlist, setSetlist] = useState([]);
  const [recommendations, setRecommendations] = useState([]);
  const [minBpm, setMinBpm] = useState(120);
  const [maxBpm, setMaxBpm] = useState(140);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  const [searchResults, setSearchResults] = useState([]);

  const searchTracks = async () => {
    if (search.trim()) {
      setIsLoading(true);
      setError(null);
      try {
        const response = await fetch(`http://localhost:8000/search/?query=${encodeURIComponent(search)}`);
        if (!response.ok) throw new Error('Search failed');
        const data = await response.json();
        setSearchResults(data);
      } catch (error) {
        console.error('Error searching tracks:', error);
        setError('Failed to search tracks. Please try again.');
      } finally {
        setIsLoading(false);
      }
    }
  };

  const addToSetlist = (track) => {
    setSetlist([...setlist, { url: track.url }]);
    setSearchResults([]);
    setSearch('');
  };

  const removeTrack = (index) => {
    const newSetlist = setlist.filter((_, i) => i !== index);
    setSetlist(newSetlist);
  };

  const generateRecommendations = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch('http://127.0.0.1:8000/generate-recommendations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          tracks: setlist,
          min_bpm: minBpm,
          max_bpm: maxBpm,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to generate recommendations');
      }

      const data = await response.json();
      setRecommendations(data);
    } catch (error) {
      console.error('Error generating recommendations:', error);
      setError('Failed to generate recommendations. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const extractDomain = (url) => {
    try {
      return new URL(url).hostname;
    } catch {
      return 'invalid-url';
    }
  };

  return (
    <div style={{
      display: 'flex',
      maxWidth: '1200px',
      margin: '0 auto',
      padding: '20px',
      fontFamily: 'Arial, sans-serif',
    }}>
      <div style={{ flex: 1, marginRight: '20px' }}>
        <h1 style={{ fontSize: '24px', marginBottom: '20px', color: '#333' }}>Setlist Creator</h1>

        <div style={{ marginBottom: '20px' }}>
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search Bandcamp tracks"
            style={{
              width: '100%',
              padding: '10px',
              marginBottom: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
            }}
          />
          <button
            onClick={searchTracks}
            style={{
              padding: '10px 20px',
              backgroundColor: '#4CAF50',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer',
            }}
          >
            Search
          </button>
        </div>

        {searchResults.length > 0 && (
          <div style={{ marginBottom: '20px' }}>
            <h3>Search Results:</h3>
            <ul style={{ listStyleType: 'none', padding: 0 }}>
              {searchResults.map((result, index) => (
                <li key={index} style={{
                  marginBottom: '10px',
                  display: 'flex',
                  alignItems: 'center',
                  backgroundColor: '#f0f0f0',
                  padding: '10px',
                  borderRadius: '4px',
                }}>
                  <span style={{ flex: 1 }}>{result.name} by {result.artist}</span>
                  <button
                    onClick={() => addToSetlist(result)}
                    style={{
                      padding: '5px 10px',
                      backgroundColor: '#008CBA',
                      color: 'white',
                      border: 'none',
                      borderRadius: '4px',
                      cursor: 'pointer',
                    }}
                  >
                    Add to Setlist
                  </button>
                </li>
              ))}
            </ul>
          </div>
        )}

        <div style={{ marginBottom: '20px' }}>
          <input
            type="number"
            value={minBpm}
            onChange={(e) => setMinBpm(parseInt(e.target.value))}
            placeholder="Min BPM"
            style={{
              width: '80px',
              padding: '10px',
              marginRight: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
            }}
          />
          <input
            type="number"
            value={maxBpm}
            onChange={(e) => setMaxBpm(parseInt(e.target.value))}
            placeholder="Max BPM"
            style={{
              width: '80px',
              padding: '10px',
              borderRadius: '4px',
              border: '1px solid #ccc',
            }}
          />
        </div>

        <button
          onClick={generateRecommendations}
          style={{
            padding: '10px 20px',
            backgroundColor: '#008CBA',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer',
          }}
        >
          Generate Recommendations
        </button>
      </div>

      <div style={{ flex: 1 }}>
        <h2 style={{ fontSize: '20px', marginBottom: '10px', color: '#333' }}>Your Setlist:</h2>
        <ul style={{ listStyleType: 'none', padding: 0 }}>
          {setlist.map((track, index) => (
            <li key={index} style={{
              marginBottom: '10px',
              display: 'flex',
              alignItems: 'center',
              backgroundColor: '#f0f0f0',
              padding: '10px',
              borderRadius: '4px',
            }}>
              <img
                src={`https://s2.googleusercontent.com/s2/favicons?domain=${extractDomain(track.url)}`}
                alt="Bandcamp icon"
                style={{ marginRight: '10px', width: '16px', height: '16px' }}
              />
              <span style={{ wordBreak: 'break-all', flex: 1 }}>{track.url}</span>
              <button
                onClick={() => removeTrack(index)}
                style={{
                  padding: '5px 10px',
                  backgroundColor: '#f44336',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  marginLeft: '10px',
                }}
              >
                Remove
              </button>
            </li>
          ))}
        </ul>

        {isLoading && <p>Loading...</p>}
        {error && <p style={{ color: 'red' }}>{error}</p>}

        <h2 style={{ fontSize: '20px', marginTop: '20px', marginBottom: '10px', color: '#333' }}>Recommendations:</h2>
        <ul style={{ listStyleType: 'none', padding: 0 }}>
          {recommendations.map((rec, index) => (
            <li key={index} style={{ marginBottom: '10px', display: 'flex', alignItems: 'center' }}>
              <img
                src={`https://s2.googleusercontent.com/s2/favicons?domain=${extractDomain(rec.url)}`}
                alt="Bandcamp icon"
                style={{ marginRight: '10px', width: '16px', height: '16px' }}
              />
              <a
                href={rec.url}
                target="_blank"
                rel="noopener noreferrer"
                style={{ color: '#0066cc', textDecoration: 'none' }}
              >
                {rec.url}
              </a>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default SetlistCreator;
